class Solution:
    def rangeBitwiseAnd(self, left: int, right: int) -> int:
        for i in reversed(range(32)):
            shifted_left = left >> i
            shifted_right = right >> i

            if shifted_left != shifted_right:
                temp = (2 ** (i+1) ) -1
                return (left & right) & ~temp

        return 0

class Solution:
    def rangeBitwiseAnd(self, left: int, right: int) -> int:
        for i in reversed(range(32)):
            shifted_left = left >> i
            shifted_right = right >> i

            if shifted_left != shifted_right:
                temp = (2 ** (i+1) ) -1
                return (left & right) & ~temp

        return left & right
